const body = $json.body;
const email = body.email;
const referral_code = body.referral_code;
const position = body.position;
const referred_by = body.referred_by;

const referralUrl = `https://YOUR_LOVABLE_URL?ref=${referral_code}`;

const emailContent = {
  to: email,
  subject: "You're on the UniMart waitlist! 🎉",
  html: `
    <div style="font-family: sans-serif; max-width: 560px; margin: 0 auto; background: #090B12; color: #E2E4EF; padding: 40px; border-radius: 16px;">
      <h1 style="color: #6C5CE7; font-size: 28px; margin-bottom: 8px;">You're in! 🚀</h1>
      <p style="color: #8890AA; font-size: 16px;">Thanks for joining the UniMart waitlist. You're <strong style="color: #fff;">#${position}</strong> in line.</p>
      <div style="background: #0D0F1C; border: 1px solid #252840; border-radius: 12px; padding: 20px; margin: 24px 0;">
        <p style="color: #6B7090; font-size: 13px; margin-bottom: 8px;">Move up the list by referring friends:</p>
        <div style="background: #090B12; border: 1px solid #6C5CE733; border-radius: 8px; padding: 12px 16px; font-family: monospace; color: #A29BFE; font-size: 14px;">${referralUrl}</div>
      </div>
      <p style="color: #6B7090; font-size: 13px;">Each friend who joins moves you <strong style="color: #A29BFE;">5 places forward</strong>.</p>
      <hr style="border-color: #181B2E; margin: 24px 0;" />
      <p style="color: #4A4F6A; font-size: 12px;">UniMart · Unsubscribe at any time</p>
    </div>
  `
};

return [{ json: { email, referral_code, position, referred_by, referralUrl, emailContent } }];
